// ══════════════════════════════════════════════════════════════
// CONFIGURATION
// ══════════════════════════════════════════════════════════════
const API_URL = "https://mv21vj2kof.execute-api.us-east-1.amazonaws.com";
const SERVICE_API_KEY = "S92QLSeIQ0faFR2ql1V066YmGRpZdME6321XLPPqPbc";
// ══════════════════════════════════════════════════════════════

const data = $input.first().json;
const value = data.body?.entry?.[0]?.changes?.[0]?.value || data.entry?.[0]?.changes?.[0]?.value;

if (!value?.messages || value.messages.length === 0) {
  return [];
}

const metadata = value.metadata || {};
const msg = value.messages[0] || {};

// Capture ID from standard buttons, lists, carousels, or quick replies
const bid = msg.interactive?.button_reply?.id || 
            msg.interactive?.list_reply?.id || 
            msg.button?.payload ||
            msg.text?.quick_reply?.payload ||
            "";

const btitle = msg.interactive?.button_reply?.title ||
               msg.interactive?.list_reply?.title ||
               "";

const messageText = msg.type === 'text'
  ? (msg.text?.body || '')
  : (btitle || (bid ? `[${bid}]` : (msg.type ? `[${msg.type}]` : '')));

return [{
  json: {
    api_url: API_URL,
    service_api_key: SERVICE_API_KEY,

    phone_number_id: metadata.phone_number_id || "",
    display_phone_number: metadata.display_phone_number || "",
    message_id: msg.id || "",
    from_number: msg.from || "",
    message_type: msg.type || "",

    action: bid.split('_')[0] || null, 
    product_id: bid.split('_')[1] || null,

    message_text: messageText,
    button_reply_id: bid,
    contact_name: value.contacts?.[0]?.profile?.name || msg.from || ""
  }
}];

const ext = $('Extract & Filter').item.json;
const msgType = ext.message_type;
const bid = (ext.button_reply_id || "").trim();
const text = (ext.message_text || "").trim().toLowerCase();

// 1. Handle Add/Remove Action (Highest Priority)
if (bid.startsWith('add_') || bid.startsWith('rem_')) {
    const extractedId = bid.split('_')[1]; 
    return [{ 
        json: { 
            route: 'add_to_cart', 
            product_id: extractedId, 
            is_button: true 
        } 
    }];
}

// 2. Handle Navigation Buttons
if (bid !== "" || msgType === 'interactive') {
    let route = 'show_options'; // Default if nothing matches

    // EXPLICIT MAPPING
    if (bid === 'order') route = 'order';
    else if (bid === 'products') route = 'products';
    else if (bid === 'view_cart') route = 'view_cart';
    else if (bid === 'more_info') route = 'more_info';
    else if (bid === 'checkout') route = 'checkout';
    else if (bid === 'new_cart') route = 'new_cart';

    return [{ json: { 
        route, 
        product_id: ext.product_id || null, 
        is_button: true 
    } }];
}

// 3. AI Fallback (Natural Language)
const menuWords = ['hi', 'hello', 'hey', 'menu', 'start', 'hola'];
if (menuWords.includes(text)) {
    return [{ json: { route: 'show_options', is_button: false } }];
}

if (text.length > 2) {
    return [{ json: { route: 'more_info', is_button: false } }];
}

return [{ json: { route: 'show_options', is_button: false } }];

const inv = $input.first().json;
const products = inv.products || inv || [];
const list = Array.isArray(products) ? products : [];
const text = list.length === 0 ? 'No products right now.' : list.map((p, i) => `${i+1}. ${p.name || p.product_name || 'Item'}${p.unit_cost != null ? ' — ' + p.unit_cost : ''}`).join('\n');
return [{ json: { output: text, product_count: list.length } }];

const ext = $('Extract & Filter').item.json;
const products = $input.first().json.products || [];
const to = (ext.from_number || '').replace(/^\+/, '');

const cards = products.slice(0, 10).map((p, i) => ({
  card_index: i,
  type: 'BUTTON', 
  header: { type: 'image', image: { link: p.image_url } },
  body: { text: `*${p.name}*\n$${p.unit_cost}` },
  action: { 
    buttons: [
      { 
        type: 'quick_reply', 
        quick_reply: { id: 'add_' + p.id, title: '➕ Add' } 
      },
      { 
        type: 'quick_reply', 
        quick_reply: { id: 'rem_' + p.id, title: '➖ Remove' } 
      }
    ] 
  }
}));

return [{ 
  json: { 
    graphPayload: {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: to,
      type: 'interactive',
      interactive: {
        type: 'carousel',
        body: { text: 'Tap + or - to manage your cart:' },
        action: { cards: cards }
      }
    } 
  } 
}];

const routeItem = $('Route').first().json;
const inv = $input.first().json;
const pid = routeItem.product_id;
const list = inv.products || inv || [];
const idx = parseInt(pid, 10);
if (!isNaN(idx) && String(idx) === pid && list[idx] != null) {
  const p = list[idx];
  return [{ json: { product_id: p.id || p.product_id } }];
}
return [{ json: { product_id: pid } }];

