const input = $input.first().json;
const action = $('Extract & Filter').item.json.action; // "add" or "rem"
let qty = input.quantity || 0; 

if (action === 'rem') {
  qty = Math.max(0, qty - 1);
} else {
  qty += 1;
}

return {
  new_quantity: qty,
  product_name: input.name,
  product_id: input.id,
  unit_cost: input.unit_cost,
  total: (qty * input.unit_cost).toFixed(2)
};

