const cartItems = $('State Manager').first().json.cart || []; 

if (cartItems.length === 0) {
    return [{ json: { summary: "Your cart is empty! 🛒", has_items: false } }];
}

let summary = "📝 *Your Current Order:*\n\n";
let total = 0;

cartItems.forEach(item => {
    const price = parseFloat(item.price) || 0;
    const qty = parseInt(item.quantity) || 1;
    summary += `• ${item.name} (x${qty}) - $${(price * qty).toFixed(2)}\n`;
    total += (price * qty);
});

summary += `\n*Total: $${total.toFixed(2)}*`;
return [{ json: { summary, has_items: true } }];

// Expand to one item per tenant so the rest of the flow runs for each business
const res = $input.first().json;
const ids = res.tenant_ids || [];
const config = $('Set API config (Phase 3)').first().json;
if (ids.length === 0) return [];
return ids.map(tenant_id => ({ json: { tenant_id, api_url: config.api_url, service_api_key: config.service_api_key } }));

// Phase 3: Find conversations that need 20h (incomplete) or 24h (closed)
const HOURS_20 = 20;
const HOURS_24 = 24;

const prev = $input.first().json;
const messages = prev.messages || [];
const tenantId = prev.tenant_id;
const apiUrl = prev.api_url;
const serviceKey = prev.service_api_key;

function norm(s) { return (s || '').replace(/\s/g, '').replace(/^\+/, '') || ''; }

// Count how often each number appears (business appears in every message)
const count = {};
for (const m of messages) {
  const from = norm(m.from_number);
  const to = norm(m.to_number);
  if (from) count[from] = (count[from] || 0) + 1;
  if (to && to !== from) count[to] = (count[to] || 0) + 1;
}
// Customer = number with fewer appearances in this tenant's messages
function customerFor(from, to) {
  if (!from) return to;
  if (!to) return from;
  return (count[from] || 0) <= (count[to] || 0) ? from : to;
}

// Group by conversation (unordered pair); keep latest message; key by customer phone
const byCustomer = {};
for (const m of messages) {
  const from = norm(m.from_number);
  const to = norm(m.to_number);
  const customer = customerFor(from, to);
  if (!customer) continue;
  const ts = m.created_ts || '';
  if (!byCustomer[customer] || ts > (byCustomer[customer].created_ts || '')) {
    byCustomer[customer] = { ...m, customer_phone: customer };
  }
}

const now = new Date();
const out = [];
for (const c of Object.values(byCustomer)) {
  const created = c.created_ts ? new Date(c.created_ts) : null;
  if (!created) continue;
  const hours = (now - created) / (1000 * 60 * 60);
  const cat = (c.category || 'active').toLowerCase();
  if (cat === 'active' && hours >= HOURS_24) {
    out.push({ api_url: apiUrl, service_api_key: serviceKey, tenant_id: tenantId, from_number: c.customer_phone, category: 'closed' });
  } else if (cat === 'active' && hours >= HOURS_20) {
    out.push({ api_url: apiUrl, service_api_key: serviceKey, tenant_id: tenantId, from_number: c.customer_phone, category: 'incomplete' });
  } else if (cat === 'incomplete' && hours >= HOURS_24) {
    out.push({ api_url: apiUrl, service_api_key: serviceKey, tenant_id: tenantId, from_number: c.customer_phone, category: 'closed' });
  }
}
return out.map(o => ({ json: o }));
